<?php

namespace App\Services;

use Illuminate\Support\Facades\Config;
use Twilio\Rest\Client;

class SmsService
{
    protected $client;
    
    public function __construct() {
        $account_sid = Config::get('services.twilio.account_sid');
        $auth_token = Config::get('services.twilio.auth_token');
        
        // Initialize a new Twilio client with your account SID and auth token
        $this->client = new Client($account_sid, $auth_token);
    }
    
    public function sendMessage(string $to, string $message) {
        try {
            $this->client->messages->create(
                $to, // Text this number
                [
                    'from' => Config::get('services.twilio.phone_number'), 
                    'body' => $message
                ]
            );
            
            return true;
        } catch (\Exception $e) {
            report($e); // Send exception to report method for logging
            return false;
        }
    }
}